        if(buf[len-1]=='\n') buf[--len]='\0';
        if(len==0) continue; // skip blank lines
        break;
    }
    bool seen[256]={false};
    int distinct=0;
    for(size_t i=0; buf[i]!='\0'; ++i){unsigned char ch=(unsigned char)buf[i]; if(!seen[ch]){seen[ch]=true; ++distinct;}}
    printf("%d\n",distinct);
}
