import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0].strip())
    idx = 1
    out = []
    for _ in range(t):
        while idx < len(data) and data[idx] == '':
            idx += 1
        if idx >= len(data):
            break
        s = data[idx]
        idx += 1
        out.append(str(len(set(s))))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

